                  <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 10, color: "white", fontWeight: 600, maxWidth: 80, overflow: "hidden", textOverflow: "ellipsis" }}>{p.name.split(" ")[0]}</span>
