const OnboardingTutorial = ({ onComplete }) => {
  const [step, setStep] = useState(0);
  const steps = [
    { icon: "✦", title: "Find Your Healer", body: "Browse verified practitioners by modality, location or rating. Filter by in-person or online.", color: COLORS.deepGreen },
    { icon: "◈", title: "Book & Attend Events", body: "Discover sound baths, retreats and workshops. Reserve your spot with a single tap.", color: "#7B5EA7" },
    { icon: "💬", title: "Connect & Communicate", body: "Message practitioners directly, ask questions and build lasting healing relationships.", color: COLORS.clay },
    { icon: "🌿", title: "Track Your Journey", body: "View your bookings, sign waivers, leave reviews and watch your healing journey unfold.", color: COLORS.sage },
  ];
  const s = steps[step];
  return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", background: COLORS.softWhite }}>
      <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "40px 32px" }}>
        <div style={{ width: 100, height: 100, borderRadius: 30, background: `linear-gradient(135deg, ${s.color}, ${s.color}99)`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 44, marginBottom: 32, boxShadow: `0 12px 32px ${s.color}40` }}>{s.icon}</div>
        <h2 style={{ fontFamily: "'Cinzel', serif", fontSize: 26, color: COLORS.deepGreen, margin: "0 0 16px", fontWeight: 600, textAlign: "center" }}>{s.title}</h2>
        <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 15, color: COLORS.sage, textAlign: "center", lineHeight: 1.7, maxWidth: 300, margin: 0 }}>{s.body}</p>
      </div>
      <div style={{ padding: "0 32px 48px" }}>
        <div style={{ display: "flex", justifyContent: "center", gap: 8, marginBottom: 24 }}>
          {steps.map((_, i) => <div key={i} style={{ width: i === step ? 24 : 8, height: 8, borderRadius: 4, background: i === step ? COLORS.deepGreen : COLORS.mist, transition: "all 0.3s" }} />)}
        </div>
        <button onClick={() => step < steps.length - 1 ? setStep(step + 1) : onComplete()} style={{ width: "100%", background: `linear-gradient(135deg, ${COLORS.deepGreen}, #7B5EA7)`, color: "white", border: "none", borderRadius: 18, padding: "18px", fontSize: 16, fontFamily: "'DM Sans', sans-serif", fontWeight: 700, cursor: "pointer", marginBottom: 12 }}>
          {step < steps.length - 1 ? "Next →" : "Get Started →"}
        </button>
        {step < steps.length - 1 && (
          <p onClick={onComplete} style={{ textAlign: "center", fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: COLORS.sage, cursor: "pointer", margin: 0 }}>Skip tutorial</p>
        )}
      </div>
    </div>
  );
};

