const ForgotPasswordScreen = ({ onBack, onReset }) => {
  const [step, setStep] = useState(1); // 1=email, 2=code, 3=newpass, 4=done
  const [email, setEmail] = useState("");
  const [code, setCode] = useState(["","","","","",""]);
  const [newPass, setNewPass] = useState("");
  const [showPass, setShowPass] = useState(false);

  const handleOtp = (val, i) => {
    const c = [...code]; c[i] = val.slice(-1); setCode(c);
    if (val && i < 5) document.getElementById("fp-otp-" + (i+1))?.focus();
  };

  return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", overflow: "hidden" }}>
      <div style={{ background: `linear-gradient(160deg, ${COLORS.deepGreen}, #0F2744)`, padding: "52px 24px 32px", flexShrink: 0 }}>
        <button onClick={step === 1 ? onBack : () => setStep(s => s - 1)} style={{ background: "rgba(255,255,255,0.12)", border: "none", borderRadius: 12, padding: "8px 14px", color: "rgba(255,255,255,0.8)", fontFamily: "'DM Sans', sans-serif", fontSize: 12, cursor: "pointer", fontWeight: 600, marginBottom: 20, display: "block" }}>← Back</button>
        <h2 style={{ color: "white", fontFamily: "'Cinzel', serif", fontSize: 26, margin: "0 0 6px", fontWeight: 600 }}>
          {step === 1 ? "Forgot Password" : step === 2 ? "Enter Code" : step === 3 ? "New Password" : "Password Reset!"}
        </h2>
        <p style={{ color: "rgba(255,255,255,0.65)", fontFamily: "'DM Sans', sans-serif", fontSize: 13, margin: 0 }}>
          {step === 1 ? "We'll send a reset code to your email" : step === 2 ? `Code sent to ${email}` : step === 3 ? "Choose a strong new password" : "Your password has been updated"}
        </p>
        <div style={{ display: "flex", gap: 6, marginTop: 20 }}>
          {[1,2,3].map(s => <div key={s} style={{ flex: 1, height: 3, borderRadius: 3, background: s <= step ? "white" : "rgba(255,255,255,0.25)", transition: "background 0.3s" }} />)}
        </div>
      </div>

      <div style={{ flex: 1, overflowY: "auto", padding: "28px 24px 60px" }}>
        {step === 1 && (
          <>
            <label style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: COLORS.sage, fontWeight: 600, letterSpacing: 1, display: "block", marginBottom: 10 }}>EMAIL ADDRESS</label>
            <div style={{ display: "flex", alignItems: "center", background: "white", border: `1.5px solid ${email ? COLORS.deepGreen : COLORS.mist}`, borderRadius: 14, padding: "14px 16px", gap: 10, marginBottom: 24 }}>
              <span style={{ fontSize: 16, opacity: 0.6 }}>✉️</span>
              <input type="email" value={email} onChange={e => setEmail(e.target.value)} placeholder="your@email.com" style={{ border: "none", outline: "none", fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: COLORS.charcoal, background: "transparent", flex: 1 }} />
            </div>
            <button onClick={() => email && setStep(2)} style={{ width: "100%", background: email ? `linear-gradient(135deg, ${COLORS.deepGreen}, #7B5EA7)` : COLORS.mist, color: "white", border: "none", borderRadius: 18, padding: "18px", fontSize: 16, fontFamily: "'DM Sans', sans-serif", fontWeight: 700, cursor: email ? "pointer" : "not-allowed" }}>Send Reset Code →</button>
          </>
        )}
        {step === 2 && (
          <>
            <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: COLORS.sage, margin: "0 0 20px", textAlign: "center" }}>Hint: use <strong>123456</strong></p>
            <div style={{ display: "flex", gap: 8, justifyContent: "center", marginBottom: 24 }}>
              {code.map((digit, i) => (
                <input key={i} id={"fp-otp-" + i} value={digit} onChange={e => handleOtp(e.target.value, i)} maxLength={1} style={{ width: 44, height: 54, textAlign: "center", border: `2px solid ${digit ? COLORS.deepGreen : COLORS.mist}`, borderRadius: 14, fontFamily: "'Cinzel', serif", fontSize: 22, fontWeight: 700, color: COLORS.charcoal, background: "white", outline: "none" }} />
              ))}
            </div>
            <button onClick={() => code.every(c => c) && setStep(3)} style={{ width: "100%", background: code.every(c => c) ? `linear-gradient(135deg, ${COLORS.deepGreen}, #7B5EA7)` : COLORS.mist, color: "white", border: "none", borderRadius: 18, padding: "18px", fontSize: 16, fontFamily: "'DM Sans', sans-serif", fontWeight: 700, cursor: code.every(c => c) ? "pointer" : "not-allowed" }}>Verify Code →</button>
          </>
        )}
        {step === 3 && (
          <>
            <label style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: COLORS.sage, fontWeight: 600, letterSpacing: 1, display: "block", marginBottom: 10 }}>NEW PASSWORD</label>
            <div style={{ display: "flex", alignItems: "center", background: "white", border: `1.5px solid ${newPass ? COLORS.deepGreen : COLORS.mist}`, borderRadius: 14, padding: "14px 16px", gap: 10, marginBottom: 8 }}>
              <span style={{ fontSize: 16, opacity: 0.6 }}>🔒</span>
              <input type={showPass ? "text" : "password"} value={newPass} onChange={e => setNewPass(e.target.value)} placeholder="Min. 8 characters" style={{ border: "none", outline: "none", fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: COLORS.charcoal, background: "transparent", flex: 1 }} />
              <span onClick={() => setShowPass(!showPass)} style={{ cursor: "pointer", flexShrink: 0 }}>
                <svg width="20" height="20" viewBox="0 0 24 24" fill="none" stroke={COLORS.sage} strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
                  {showPass ? <><path d="M17.94 17.94A10.07 10.07 0 0112 20c-7 0-11-8-11-8a18.45 18.45 0 015.06-5.94"/><path d="M9.9 4.24A9.12 9.12 0 0112 4c7 0 11 8 11 8a18.5 18.5 0 01-2.16 3.19"/><line x1="1" y1="1" x2="23" y2="23"/></> : <><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z"/><circle cx="12" cy="12" r="3"/></>}
                </svg>
              </span>
            </div>
            {newPass.length > 0 && (
              <div style={{ marginBottom: 20 }}>
                <div style={{ display: "flex", gap: 4, marginBottom: 4 }}>
                  {[1,2,3,4].map(i => <div key={i} style={{ flex: 1, height: 3, borderRadius: 2, background: newPass.length >= i * 2 ? (newPass.length >= 8 ? COLORS.deepGreen : COLORS.gold) : COLORS.mist, transition: "background 0.3s" }} />)}
                </div>
                <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: COLORS.sage, margin: 0 }}>{newPass.length < 6 ? "Weak" : newPass.length < 8 ? "Getting there..." : "Strong ✓"}</p>
              </div>
            )}
            <button onClick={() => newPass.length >= 8 && setStep(4)} style={{ width: "100%", background: newPass.length >= 8 ? `linear-gradient(135deg, ${COLORS.deepGreen}, #7B5EA7)` : COLORS.mist, color: "white", border: "none", borderRadius: 18, padding: "18px", fontSize: 16, fontFamily: "'DM Sans', sans-serif", fontWeight: 700, cursor: newPass.length >= 8 ? "pointer" : "not-allowed", marginTop: 8 }}>Reset Password →</button>
          </>
        )}
        {step === 4 && (
          <div style={{ textAlign: "center", padding: "20px 0" }}>
            <div style={{ width: 80, height: 80, borderRadius: 24, background: `linear-gradient(135deg, ${COLORS.deepGreen}, #7B5EA7)`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 38, margin: "0 auto 20px" }}>✅</div>
            <h3 style={{ fontFamily: "'Cinzel', serif", fontSize: 22, color: COLORS.deepGreen, margin: "0 0 10px", fontWeight: 600 }}>Password Updated!</h3>
            <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: COLORS.sage, margin: "0 0 28px" }}>Your password has been reset successfully.</p>
            <button onClick={onReset} style={{ width: "100%", background: `linear-gradient(135deg, ${COLORS.deepGreen}, #7B5EA7)`, color: "white", border: "none", borderRadius: 16, padding: "16px", fontSize: 15, fontFamily: "'DM Sans', sans-serif", fontWeight: 600, cursor: "pointer" }}>Sign In →</button>
          </div>
        )}
      </div>
    </div>
  );
};


// ── STRIPE PAYMENT ───────────────────────────────────────────────────────────

const STRIPE_PK = "pk_live_51TdCvCFted6WrIY4Atzad2H6Z8xw0vNB59s3EXTG1SV9Epo3sd4Y7asTT0nGAvYP2sSa3kp7kVSjDv1i7j5ygaRl00KGF3itbm";

const StripePaymentForm = ({ amount, practitioner, date, time, disabled, onSuccess }) => {
  const [step, setStep] = useState("idle");
  const [cardNumber, setCardNumber] = useState("");
  const [expiry, setExpiry] = useState("");
  const [cvc, setCvc] = useState("");
  const [name, setName] = useState("");
  const [error, setError] = useState("");

  useEffect(() => {
    if (window.Stripe) return;
    const script = document.createElement("script");
    script.src = "https://js.stripe.com/v3/";
    document.head.appendChild(script);
  }, []);

  const formatCard = (val) => val.replace(/\D/g,"").slice(0,16).replace(/(.{4})/g,"$1 ").trim();
  const formatExpiry = (val) => { const v = val.replace(/\D/g,"").slice(0,4); return v.length>=3 ? v.slice(0,2)+"/"+v.slice(2) : v; };

  const handlePay = async () => {
    if (!name || cardNumber.replace(/\s/g,"").length < 16 || expiry.length < 5 || cvc.length < 3) {
      setError("Please fill in all card details."); return;
    }
    setError(""); setStep("processing");
    try {
      const stripe = window.Stripe(STRIPE_PK);
      const [expM, expY] = expiry.split("/");
      const { paymentMethod, error: pmError } = await stripe.createPaymentMethod({
        type: "card",
        card: { number: cardNumber.replace(/\s/g,""), exp_month: parseInt(expM), exp_year: parseInt("20"+expY), cvc },
        billing_details: { name },
      });
      if (pmError) { setError(pmError.message); setStep("form"); return; }
      setStep("done");
      sendBookingEmail("Client", "soulremembrance@outlook.com", practitioner?.name || "Practitioner", practitioner?.title || "Session", date || "TBC", time || "TBC", amount);
      setTimeout(() => onSuccess(), 1500);
    } catch(e) { setError("Payment failed. Please try again."); setStep("form"); }
  };

  if (step === "done") return (
    <div style={{ background: "#E8F5E9", borderRadius: 16, padding: "20px", textAlign: "center" }}>
      <p style={{ fontSize: 32, marginBottom: 8 }}>✅</p>
      <p style={{ fontFamily: "DM Sans, sans-serif", fontSize: 15, fontWeight: 700, color: "#2E7D32", margin: "0 0 4px" }}>Payment Successful!</p>
      <p style={{ fontFamily: "DM Sans, sans-serif", fontSize: 13, color: "#388E3C" }}>Your booking is confirmed</p>
    </div>
  );

  if (step === "processing") return (
    <div style={{ background: COLORS.cream, borderRadius: 16, padding: "24px", textAlign: "center" }}>
      <p style={{ fontSize: 28, marginBottom: 8 }}>💳</p>
      <p style={{ fontFamily: "DM Sans, sans-serif", fontSize: 14, color: COLORS.deepGreen, fontWeight: 600 }}>Processing payment...</p>
    </div>
  );

  if (step === "form") return (
    <div style={{ background: "white", borderRadius: 18, padding: "20px", boxShadow: "0 4px 16px rgba(0,0,0,0.08)", border: "1px solid " + COLORS.cream }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
        <p style={{ fontFamily: "DM Sans, sans-serif", fontSize: 11, color: COLORS.sage, letterSpacing: 1.5, fontWeight: 700, margin: 0 }}>CARD DETAILS</p>
        <span style={{ fontSize: 16 }}>🔒</span>
      </div>
      <input value={name} onChange={e=>setName(e.target.value)} placeholder="Name on card" style={{ width:"100%", border:"1.5px solid "+(name?COLORS.deepGreen:COLORS.mist), borderRadius:12, padding:"12px 14px", fontFamily:"DM Sans, sans-serif", fontSize:14, color:COLORS.charcoal, background:COLORS.cream, outline:"none", boxSizing:"border-box", marginBottom:12 }} />
      <input value={cardNumber} onChange={e=>setCardNumber(formatCard(e.target.value))} placeholder="Card number" style={{ width:"100%", border:"1.5px solid "+(cardNumber?COLORS.deepGreen:COLORS.mist), borderRadius:12, padding:"12px 14px", fontFamily:"DM Sans, sans-serif", fontSize:14, color:COLORS.charcoal, background:COLORS.cream, outline:"none", boxSizing:"border-box", letterSpacing:2, marginBottom:12 }} />
      <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:10, marginBottom:16 }}>
        <input value={expiry} onChange={e=>setExpiry(formatExpiry(e.target.value))} placeholder="MM/YY" style={{ border:"1.5px solid "+(expiry?COLORS.deepGreen:COLORS.mist), borderRadius:12, padding:"12px 14px", fontFamily:"DM Sans, sans-serif", fontSize:14, color:COLORS.charcoal, background:COLORS.cream, outline:"none", boxSizing:"border-box" }} />
        <input value={cvc} onChange={e=>setCvc(e.target.value.replace(/\D/g,"").slice(0,4))} placeholder="CVC" style={{ border:"1.5px solid "+(cvc?COLORS.deepGreen:COLORS.mist), borderRadius:12, padding:"12px 14px", fontFamily:"DM Sans, sans-serif", fontSize:14, color:COLORS.charcoal, background:COLORS.cream, outline:"none", boxSizing:"border-box" }} />
      </div>
      {error && <div style={{ background:"#FFEBEE", borderRadius:10, padding:"10px 14px", marginBottom:12 }}><p style={{ fontFamily:"DM Sans, sans-serif", fontSize:13, color:"#C62828", margin:0 }}>{error}</p></div>}
      <button onClick={handlePay} style={{ width:"100%", background:"linear-gradient(135deg,"+COLORS.deepGreen+",#7B5EA7)", color:"white", border:"none", borderRadius:14, padding:"16px", fontSize:15, fontFamily:"DM Sans, sans-serif", fontWeight:700, cursor:"pointer" }}>
        Pay £{amount} Securely →
      </button>
      <p style={{ fontFamily:"DM Sans, sans-serif", fontSize:11, color:COLORS.sage, textAlign:"center", margin:"10px 0 0" }}>🔒 Secured by Stripe</p>
    </div>
  );

  return (
    <button onClick={() => !disabled && setStep("form")} style={{ width:"100%", background:disabled?COLORS.mist:"linear-gradient(135deg,"+COLORS.deepGreen+",#7B5EA7)", color:"white", border:"none", borderRadius:16, padding:"18px", fontSize:16, fontFamily:"DM Sans, sans-serif", fontWeight:700, cursor:disabled?"not-allowed":"pointer" }}>
      {disabled ? "Select a date & time" : "Confirm & Pay £"+amount+" →"}
    </button>
  );
};

