const MeditationScreen = ({ onBack }) => {
  const [view, setView] = useState("home"); // home | play | complete
  const [active, setActive] = useState(null);
  const [playState, setPlayState] = useState("idle"); // idle | playing | paused | done
  const [elapsed, setElapsed] = useState(0);
  const [currentStep, setCurrentStep] = useState(0);
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [completedIds, setCompletedIds] = useState([1, 3]);
  const timerRef = useState(null);

  const TOTAL = 360; // 6 minutes in seconds
  const stepDuration = Math.floor(TOTAL / 8); // ~45s per step

  const categories = ["All", "Morning", "Healing", "Love", "Grounding", "Visualisation", "Energy", "Spiritual", "Gratitude"];
  const filtered = selectedCategory === "All" ? MEDITATIONS : MEDITATIONS.filter(m => m.category === selectedCategory);

  const startMeditation = (m) => {
    setActive(m);
    setElapsed(0);
    setCurrentStep(0);
    setPlayState("idle");
    setView("play");
  };

  const formatTime = (s) => `${Math.floor(s / 60)}:${String(s % 60).padStart(2, "0")}`;
  const progress = elapsed / TOTAL;
  const stepIndex = Math.min(Math.floor(elapsed / stepDuration), 7);

  const handleTick = () => {
    setElapsed(prev => {
      const next = prev + 1;
      setCurrentStep(Math.min(Math.floor(next / stepDuration), 7));
      if (next >= TOTAL) {
        setPlayState("done");
        setCompletedIds(ids => active && !ids.includes(active.id) ? [...ids, active.id] : ids);
        return TOTAL;
      }
      return next;
    });
  };

  // Completion screen
  if (view === "complete" && active) return (
    <div style={{ height: "100%", display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "40px 32px", background: `linear-gradient(160deg, ${active.color}20, ${COLORS.softWhite})` }}>
      <div style={{ width: 90, height: 90, borderRadius: 28, background: `linear-gradient(135deg, ${active.color}, ${active.color}99)`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 42, marginBottom: 24, boxShadow: `0 12px 32px ${active.color}50` }}>{active.icon}</div>
      <h2 style={{ fontFamily: "'Cinzel', serif", fontSize: 26, color: COLORS.deepGreen, margin: "0 0 10px", fontWeight: 600, textAlign: "center" }}>Session Complete</h2>
      <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 15, color: COLORS.sage, textAlign: "center", lineHeight: 1.7, marginBottom: 8 }}>{active.title}</p>
      <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: COLORS.sage, textAlign: "center", marginBottom: 32 }}>6 minutes · {completedIds.length} of 10 completed</p>
      <div style={{ width: "100%", background: COLORS.cream, borderRadius: 10, height: 6, marginBottom: 32 }}>
        <div style={{ height: 6, borderRadius: 6, background: `linear-gradient(90deg, ${COLORS.deepGreen}, #7B5EA7)`, width: `${(completedIds.length / 10) * 100}%`, transition: "width 0.5s ease" }} />
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 12, width: "100%" }}>
        <button onClick={() => { setView("home"); setActive(null); setElapsed(0); setPlayState("idle"); }} style={{ width: "100%", background: `linear-gradient(135deg, ${COLORS.deepGreen}, #7B5EA7)`, color: "white", border: "none", borderRadius: 16, padding: "16px", fontSize: 15, fontFamily: "'DM Sans', sans-serif", fontWeight: 700, cursor: "pointer" }}>Back to Meditations</button>
        <button onClick={onBack} style={{ width: "100%", background: "white", color: COLORS.deepGreen, border: `1.5px solid ${COLORS.deepGreen}`, borderRadius: 16, padding: "15px", fontSize: 14, fontFamily: "'DM Sans', sans-serif", fontWeight: 600, cursor: "pointer" }}>Return to Profile</button>
      </div>
    </div>
  );

  // Player screen
  if (view === "play" && active) {
    const circumference = 2 * Math.PI * 100;
    const strokeDash = circumference * (1 - progress);

    return (
      <div style={{ height: "100%", display: "flex", flexDirection: "column", background: `linear-gradient(170deg, ${COLORS.deepGreen} 0%, #1A0F3D 50%, ${active.color}80 100%)`, overflow: "hidden" }}>
        {/* Header */}
        <div style={{ padding: "52px 24px 0", display: "flex", justifyContent: "space-between", alignItems: "center", flexShrink: 0 }}>
          <button onClick={() => { setView("home"); setPlayState("idle"); setElapsed(0); }} style={{ background: "rgba(255,255,255,0.12)", border: "none", borderRadius: 10, padding: "8px 14px", color: "white", fontFamily: "'DM Sans', sans-serif", fontSize: 12, cursor: "pointer", fontWeight: 600 }}>✕ End</button>
          <p style={{ color: "rgba(255,255,255,0.6)", fontFamily: "'DM Sans', sans-serif", fontSize: 12, margin: 0 }}>{active.category} · 6 min</p>
          <div style={{ width: 60 }} />
        </div>

        {/* Circular timer */}
        <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", padding: "0 32px" }}>
          <div style={{ position: "relative", width: 230, height: 230, marginBottom: 32 }}>
            <svg width="230" height="230" viewBox="0 0 230 230" style={{ transform: "rotate(-90deg)" }}>
              <circle cx="115" cy="115" r="100" fill="none" stroke="rgba(255,255,255,0.08)" strokeWidth="8" />
              <circle cx="115" cy="115" r="100" fill="none" stroke={active.color} strokeWidth="8"
                strokeDasharray={circumference} strokeDashoffset={strokeDash}
                strokeLinecap="round" style={{ transition: "stroke-dashoffset 0.8s ease", filter: `drop-shadow(0 0 12px ${active.color})` }} />
            </svg>
            <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
              <span style={{ fontSize: 44, marginBottom: 8 }}>{active.icon}</span>
              <span style={{ fontFamily: "'Cinzel', serif", fontSize: 32, fontWeight: 700, color: "white" }}>{formatTime(TOTAL - elapsed)}</span>
              <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: "rgba(255,255,255,0.5)", marginTop: 4 }}>remaining</span>
            </div>
          </div>

          {/* Title */}
          <h2 style={{ fontFamily: "'Cinzel', serif", fontSize: 22, color: "white", margin: "0 0 6px", fontWeight: 600, textAlign: "center" }}>{active.title}</h2>
          <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: "rgba(255,255,255,0.55)", margin: "0 0 28px", textAlign: "center" }}>{active.subtitle}</p>

          {/* Current step guidance */}
          <div style={{ background: "rgba(255,255,255,0.08)", borderRadius: 18, padding: "18px 20px", width: "100%", backdropFilter: "blur(10px)", border: "1px solid rgba(255,255,255,0.1)", marginBottom: 28, minHeight: 80 }}>
            <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 14, color: "white", textAlign: "center", lineHeight: 1.7, margin: 0 }}>
              {playState === "idle" ? active.description : (active.steps[currentStep] || active.steps[7])}
            </p>
          </div>

          {/* Step dots */}
          <div style={{ display: "flex", gap: 6, marginBottom: 32 }}>
            {active.steps.map((_, i) => (
              <div key={i} style={{ width: i === stepIndex && playState === "playing" ? 20 : 8, height: 8, borderRadius: 4, background: i < stepIndex ? active.color : i === stepIndex && playState === "playing" ? "white" : "rgba(255,255,255,0.2)", transition: "all 0.4s ease" }} />
            ))}
          </div>

          {/* Controls */}
          <div style={{ display: "flex", gap: 20, alignItems: "center" }}>
            <button onClick={() => { setElapsed(0); setCurrentStep(0); setPlayState("idle"); }} style={{ width: 48, height: 48, borderRadius: "50%", background: "rgba(255,255,255,0.12)", border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="white"><path d="M6 6h2v12H6zm3.5 6 8.5 6V6z"/></svg>
            </button>

            {playState === "done" ? (
              <button onClick={() => setView("complete")} style={{ width: 72, height: 72, borderRadius: "50%", background: `linear-gradient(135deg, ${active.color}, ${active.color}cc)`, border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: `0 8px 24px ${active.color}60` }}>
                <span style={{ fontSize: 28 }}>✓</span>
              </button>
            ) : (
              <button
                onClick={() => {
                  if (playState === "idle" || playState === "paused") {
                    setPlayState("playing");
                    const interval = setInterval(() => {
                      handleTick();
                    }, 1000);
                    timerRef[1](interval);
                  } else {
                    setPlayState("paused");
                    clearInterval(timerRef[0]);
                  }
                }}
                style={{ width: 72, height: 72, borderRadius: "50%", background: `linear-gradient(135deg, ${active.color}, ${active.color}cc)`, border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center", boxShadow: `0 8px 24px ${active.color}60` }}>
                {playState === "playing" ? (
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="white"><path d="M6 19h4V5H6v14zm8-14v14h4V5h-4z"/></svg>
                ) : (
                  <svg width="24" height="24" viewBox="0 0 24 24" fill="white"><path d="M8 5v14l11-7z"/></svg>
                )}
              </button>
            )}

            <button onClick={() => { setElapsed(Math.min(elapsed + 30, TOTAL)); }} style={{ width: 48, height: 48, borderRadius: "50%", background: "rgba(255,255,255,0.12)", border: "none", cursor: "pointer", display: "flex", alignItems: "center", justifyContent: "center" }}>
              <svg width="20" height="20" viewBox="0 0 24 24" fill="white"><path d="M18 6v12h-2V6zm-3.5 6L6 6v12z"/></svg>
            </button>
          </div>
        </div>
      </div>
    );
  }

  // Home / browse screen
  return (
    <div style={{ paddingBottom: 90 }}>
      <div style={{ background: `linear-gradient(160deg, ${COLORS.deepGreen}, #1A0F3D)`, padding: "52px 24px 28px", position: "relative", overflow: "hidden" }}>
        <div style={{ position: "absolute", top: -40, right: -40, width: 160, height: 160, borderRadius: "50%", background: "rgba(155,127,212,0.12)" }} />
        <div style={{ position: "absolute", bottom: -20, left: -20, width: 120, height: 120, borderRadius: "50%", background: "rgba(212,168,67,0.08)" }} />
        <button onClick={onBack} style={{ background: "rgba(255,255,255,0.15)", border: "1px solid rgba(255,255,255,0.3)", borderRadius: 12, padding: "9px 16px", color: "white", fontFamily: "'DM Sans', sans-serif", fontSize: 13, cursor: "pointer", fontWeight: 600, marginBottom: 16, display: "block" }}>← Back</button>
        <h2 style={{ color: "white", fontFamily: "'Cinzel', serif", fontSize: 28, margin: "0 0 4px", fontWeight: 600 }}>Guided Meditations</h2>
        <p style={{ color: "rgba(255,255,255,0.65)", fontFamily: "'DM Sans', sans-serif", fontSize: 13, margin: "0 0 16px" }}>10 meditations · 6 minutes each</p>

        {/* Progress bar */}
        <div style={{ background: "rgba(255,255,255,0.1)", borderRadius: 14, padding: "14px 16px" }}>
          <div style={{ display: "flex", justifyContent: "space-between", marginBottom: 8 }}>
            <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: "rgba(255,255,255,0.7)", fontWeight: 600 }}>Your progress</span>
            <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: "white", fontWeight: 700 }}>{completedIds.length} / 10 complete</span>
          </div>
          <div style={{ background: "rgba(255,255,255,0.15)", borderRadius: 6, height: 8 }}>
            <div style={{ height: 8, borderRadius: 6, background: `linear-gradient(90deg, ${COLORS.gold}, #7B5EA7)`, width: `${(completedIds.length / 10) * 100}%`, transition: "width 0.5s ease" }} />
          </div>
        </div>
      </div>

      {/* Category filter */}
      <div style={{ background: "white", borderBottom: `1px solid ${COLORS.cream}`, padding: "12px 0 12px 16px" }}>
        <div style={{ display: "flex", gap: 8, overflowX: "auto", scrollbarWidth: "none", paddingRight: 16 }}>
          {categories.map(cat => (
            <div key={cat} onClick={() => setSelectedCategory(cat)} style={{ flexShrink: 0, background: selectedCategory === cat ? COLORS.deepGreen : COLORS.cream, color: selectedCategory === cat ? "white" : COLORS.charcoal, borderRadius: 20, padding: "7px 14px", fontSize: 12, fontFamily: "'DM Sans', sans-serif", fontWeight: selectedCategory === cat ? 600 : 400, cursor: "pointer" }}>{cat}</div>
          ))}
        </div>
      </div>

      {/* Meditation cards */}
      <div style={{ padding: "16px 20px", display: "flex", flexDirection: "column", gap: 12 }}>
        {filtered.map((m, idx) => {
          const done = completedIds.includes(m.id);
          return (
            <div key={m.id} onClick={() => startMeditation(m)} style={{ background: "white", borderRadius: 20, overflow: "hidden", boxShadow: "0 3px 16px rgba(0,0,0,0.08)", border: `1px solid ${done ? m.color + "40" : COLORS.cream}`, cursor: "pointer" }}>
              <div style={{ background: `linear-gradient(135deg, ${m.color}, ${m.color}aa)`, padding: "16px 18px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
                <div style={{ display: "flex", gap: 12, alignItems: "center" }}>
                  <div style={{ width: 48, height: 48, borderRadius: 15, background: "rgba(255,255,255,0.2)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 26 }}>{m.icon}</div>
                  <div>
                    <div style={{ display: "flex", gap: 6, alignItems: "center", marginBottom: 2 }}>
                      <h3 style={{ color: "white", fontFamily: "'Cinzel', serif", fontSize: 16, margin: 0, fontWeight: 600 }}>{m.title}</h3>
                      {done && <span style={{ background: "rgba(255,255,255,0.25)", color: "white", fontSize: 9, padding: "2px 7px", borderRadius: 10, fontFamily: "'DM Sans', sans-serif", fontWeight: 700 }}>✓ DONE</span>}
                    </div>
                    <p style={{ color: "rgba(255,255,255,0.75)", fontFamily: "'DM Sans', sans-serif", fontSize: 12, margin: 0 }}>{m.subtitle}</p>
                  </div>
                </div>
                <div style={{ textAlign: "right", flexShrink: 0 }}>
                  <p style={{ color: "white", fontFamily: "'Cinzel', serif", fontSize: 16, fontWeight: 700, margin: "0 0 2px" }}>6 min</p>
                  <p style={{ color: "rgba(255,255,255,0.6)", fontFamily: "'DM Sans', sans-serif", fontSize: 10, margin: 0 }}>{m.category}</p>
                </div>
              </div>
              <div style={{ padding: "12px 18px" }}>
                <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, color: COLORS.sage, margin: 0, lineHeight: 1.5, display: "-webkit-box", WebkitLineClamp: 2, WebkitBoxOrient: "vertical", overflow: "hidden" }}>{m.description}</p>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
};


