const DASH_DOC_TYPES = [
  { id: "qualification", label: "Qualification / Certificate", icon: "🎓", color: "#2D1B69" },
  { id: "insurance",     label: "Professional Insurance",       icon: "🛡️", color: "#C9A84C" },
  { id: "membership",   label: "Professional Body Membership", icon: "🏛️", color: "#9B7FD4" },
  { id: "dbs",          label: "DBS / Background Check",       icon: "✅", color: "#D4A843" },
];

const DashboardDocuments = () => {
  const [docs, setDocs] = useState([
    { id: 1, icon: "🎓", name: "Sound Healing Certificate", issuer: "College of Sound Healing", expiry: "No expiry", status: "approved", fileName: "sound_healing_cert.pdf" },
    { id: 2, icon: "🛡️", name: "Professional Indemnity Insurance", issuer: "Balens Ltd", expiry: "Exp: Dec 2025", status: "approved", fileName: "balens_insurance_2025.pdf" },
    { id: 3, icon: "🏛️", name: "CNHC Registration", issuer: "Complementary & Natural Healthcare Council", expiry: "Exp: Mar 2026", status: "pending", fileName: "" },
    { id: 4, icon: "✅", name: "Enhanced DBS Certificate", issuer: "DBS Update Service", expiry: "Exp: Jan 2026", status: "approved", fileName: "dbs_certificate.pdf" },
  ]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newDocType, setNewDocType] = useState(null);
  const [newFileName, setNewFileName] = useState("");

  const handleAddFile = (e) => {
    const file = e.target.files[0];
    if (file) setNewFileName(file.name);
  };

  const confirmAdd = () => {
    if (!newDocType) return;
    const dtype = DASH_DOC_TYPES.find(d => d.id === newDocType);
    setDocs([...docs, { id: Date.now(), icon: dtype.icon, name: dtype.label, issuer: "", expiry: "", status: "pending", fileName: newFileName }]);
    setShowAddModal(false);
    setNewDocType(null);
    setNewFileName("");
  };

  const handleFileReplace = (docId, file) => {
    setDocs(docs.map(d => d.id === docId ? { ...d, fileName: file.name, status: "pending" } : d));
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12, position: "relative" }}>
      {/* Info banner */}
      <div style={{ background: `${COLORS.deepGreen}10`, border: `1px solid ${COLORS.mist}`, borderRadius: 14, padding: "14px 16px", display: "flex", gap: 12, alignItems: "flex-start" }}>
        <span style={{ fontSize: 20, flexShrink: 0 }}>🔒</span>
        <div>
          <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, fontWeight: 600, color: COLORS.deepGreen, margin: "0 0 3px" }}>Verified credentials build trust</p>
          <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: COLORS.sage, margin: 0, lineHeight: 1.5 }}>Approved documents unlock your verified badge and boost your profile ranking.</p>
        </div>
      </div>

      {/* Header row */}
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: COLORS.sage, letterSpacing: 1.5, margin: 0, fontWeight: 600 }}>MY DOCUMENTS ({docs.length})</p>
        <label htmlFor="dash-upload-trigger" onClick={() => setShowAddModal(true)} style={{ background: COLORS.deepGreen, borderRadius: 20, padding: "6px 14px", cursor: "pointer", display: "inline-block" }}>
          <span style={{ color: "white", fontFamily: "'DM Sans', sans-serif", fontSize: 11, fontWeight: 600 }}>+ Upload New</span>
        </label>
      </div>

      {/* Existing documents */}
      {docs.map(doc => (
        <div key={doc.id} style={{ background: "white", borderRadius: 16, padding: "15px 16px", boxShadow: "0 2px 10px rgba(0,0,0,0.05)", border: `1px solid ${COLORS.cream}` }}>
          <div style={{ display: "flex", gap: 12, alignItems: "center", marginBottom: doc.fileName ? 10 : 0 }}>
            <div style={{ width: 42, height: 42, borderRadius: 12, background: COLORS.cream, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 22, flexShrink: 0 }}>{doc.icon}</div>
            <div style={{ flex: 1 }}>
              <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, fontWeight: 600, color: COLORS.charcoal, margin: "0 0 2px" }}>{doc.name}</p>
              <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: COLORS.sage, margin: "0 0 6px" }}>{doc.issuer || "No issuer added"}</p>
              <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
                {doc.expiry && <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 10, color: COLORS.sage, background: COLORS.cream, padding: "3px 8px", borderRadius: 10 }}>{doc.expiry}</span>}
                <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 10, fontWeight: 600, padding: "3px 10px", borderRadius: 10, background: doc.status === "approved" ? "#EEE5FF" : "#FFF8EE", color: doc.status === "approved" ? COLORS.deepGreen : COLORS.gold }}>
                  {doc.status === "approved" ? "✓ Verified" : "⏳ Pending review"}
                </span>
              </div>
            </div>
          </div>

          {/* File row */}
          <label htmlFor={`dash-file-${doc.id}`} style={{ display: "flex", alignItems: "center", gap: 10, background: doc.fileName ? `${COLORS.deepGreen}08` : COLORS.cream, border: `1.5px dashed ${doc.fileName ? COLORS.deepGreen : COLORS.mist}`, borderRadius: 12, padding: "10px 14px", cursor: "pointer" }}>
            <span style={{ fontSize: 16 }}>{doc.fileName ? "📄" : "📎"}</span>
            <div style={{ flex: 1, minWidth: 0 }}>
              <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, fontWeight: 600, color: COLORS.deepGreen, margin: 0, overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap" }}>
                {doc.fileName ? doc.fileName : "Tap to upload file"}
              </p>
              <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 10, color: COLORS.sage, margin: "1px 0 0" }}>
                {doc.fileName ? "Tap to replace" : "PDF, JPG or PNG · Max 10MB"}
              </p>
            </div>
            {doc.fileName && <span style={{ color: COLORS.deepGreen, fontSize: 11, fontWeight: 600, flexShrink: 0 }}>Replace</span>}
          </label>
          <input id={`dash-file-${doc.id}`} type="file" accept=".pdf,.jpg,.jpeg,.png" onChange={e => { if (e.target.files[0]) handleFileReplace(doc.id, e.target.files[0]); }} style={{ display: "none" }} />
        </div>
      ))}

      {/* Add new document modal */}
      {showAddModal && (
        <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,0.5)", zIndex: 200, display: "flex", alignItems: "flex-end", justifyContent: "center" }}>
          <div style={{ background: "white", borderRadius: "24px 24px 0 0", padding: "24px 24px 40px", width: 390, maxHeight: "80vh", overflowY: "auto" }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
              <h3 style={{ fontFamily: "'Cinzel', serif", fontSize: 22, fontWeight: 600, color: COLORS.deepGreen, margin: 0 }}>Upload Document</h3>
              <span onClick={() => { setShowAddModal(false); setNewDocType(null); setNewFileName(""); }} style={{ fontSize: 20, cursor: "pointer", color: COLORS.sage }}>✕</span>
            </div>

            <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: COLORS.sage, letterSpacing: 1.5, margin: "0 0 12px", fontWeight: 600 }}>SELECT TYPE</p>
            <div style={{ display: "flex", flexDirection: "column", gap: 8, marginBottom: 20 }}>
              {DASH_DOC_TYPES.map(dt => (
                <div key={dt.id} onClick={() => setNewDocType(dt.id)} style={{ display: "flex", alignItems: "center", gap: 12, background: newDocType === dt.id ? `${COLORS.deepGreen}10` : COLORS.cream, border: `1.5px solid ${newDocType === dt.id ? COLORS.deepGreen : "transparent"}`, borderRadius: 14, padding: "13px 16px", cursor: "pointer" }}>
                  <div style={{ width: 38, height: 38, borderRadius: 11, background: `${dt.color}15`, display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20 }}>{dt.icon}</div>
                  <span style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 13, fontWeight: newDocType === dt.id ? 600 : 400, color: COLORS.charcoal }}>{dt.label}</span>
                  {newDocType === dt.id && <span style={{ marginLeft: "auto", color: COLORS.deepGreen, fontWeight: 700 }}>✓</span>}
                </div>
              ))}
            </div>

            <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 11, color: COLORS.sage, letterSpacing: 1.5, margin: "0 0 10px", fontWeight: 600 }}>ATTACH FILE</p>
            <label htmlFor="new-doc-file" style={{ display: "flex", alignItems: "center", gap: 10, background: newFileName ? `${COLORS.deepGreen}08` : COLORS.cream, border: `1.5px dashed ${newFileName ? COLORS.deepGreen : COLORS.mist}`, borderRadius: 14, padding: "16px", cursor: "pointer", marginBottom: 20 }}>
              <span style={{ fontSize: 22 }}>{newFileName ? "📄" : "📎"}</span>
              <div>
                <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 14, fontWeight: 600, color: COLORS.deepGreen, margin: 0 }}>{newFileName || "Tap to choose file"}</p>
                <p style={{ fontFamily: "'DM Sans', sans-serif", fontSize: 12, color: COLORS.sage, margin: "2px 0 0" }}>{newFileName ? "File selected ✓" : "PDF, JPG or PNG · Max 10MB"}</p>
              </div>
            </label>
            <input id="new-doc-file" type="file" accept=".pdf,.jpg,.jpeg,.png" onChange={handleAddFile} style={{ display: "none" }} />

            <button onClick={confirmAdd} style={{ width: "100%", background: newDocType ? `linear-gradient(135deg, ${COLORS.deepGreen}, #7B5EA7)` : COLORS.mist, color: "white", border: "none", borderRadius: 16, padding: "16px", fontSize: 15, fontFamily: "'DM Sans', sans-serif", fontWeight: 600, cursor: newDocType ? "pointer" : "not-allowed" }}>
              {newDocType ? "Upload Document →" : "Select a document type first"}
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

