        <div style={{ display: "flex", alignItems: "center", gap: 14 }}>
          <div style={{ width: 52, height: 52, borderRadius: 14, overflow: "hidden", border: "1.5px solid rgba(255,255,255,0.2)", boxShadow: "0 4px 16px rgba(0,0,0,0.2)" }}>
          <img src={COASTAL_IMG} alt="Soul Remembrance" style={{ width: "100%", height: "100%", objectFit: "cover", objectPosition: "center 40%" }} />
        </div>
          <div>
            <h2 style={{ color: "white", fontFamily: "'Cinzel', serif", fontSize: 28, margin: 0, fontWeight: 600 }}>Welcome back</h2>
            <p style={{ color: "rgba(255,255,255,0.6)", fontFamily: "'DM Sans', sans-serif", fontSize: 13, margin: "3px 0 0" }}>Soul Remembrance</p>
          </div>
        </div>
